const body = $json.body || $json;
const blog_url = body.blog_url || '';
if (!blog_url) {
  return [{ json: { ok: false, message: 'blog_url is required' } }];
}
return [{ json: { ok: true, blog_url, idea_id: body.idea_id || `BLOG-${Date.now()}`, raw_input: body.raw_input || '' } }];

const payload = JSON.stringify($json);
const text = payload.replace(/<script[\s\S]*?<\/script>/gi, ' ').replace(/<style[\s\S]*?<\/style>/gi, ' ').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
const row = $item(0).$node['Validate Input'].json;
return [{ json: { ...row, article_text: text.slice(0, 16000) } }];

