parameters.jsCode:
const raw = $json.output?.[0]?.content?.[0]?.text || '{}';
const clean = raw.replace(/^```json\s*/i, '').replace(/```$/i, '').trim();
let parsed = {};
try { parsed = JSON.parse(clean); } catch (e) { parsed = { posts: [], hooks: [], founder_note: '', carousel_outline: [] }; }
const base = $item(0).$node['Extract Text'].json;
const out = [];
(parsed.posts || []).slice(0, 5).forEach((p, idx) => {
  out.push({ json: {
    idea_id: `${base.idea_id}-P${idx + 1}`,
    created_at: new Date().toISOString().slice(0, 10),
    source_type: 'blog',
    source_link: base.blog_url,
    raw_input: base.raw_input,
    title: p.title || `Blog Post ${idx + 1}`,
    draft_text: p.post_body || '',
    bucket: p.bucket || 'What Changed In AI',
    status: 'needs_review',
    reviewer: '',
    review_notes: ''
  }});
});
out.push({ json: {
  idea_id: `${base.idea_id}-FN1`,
  created_at: new Date().toISOString().slice(0, 10),
  source_type: 'blog',
  source_link: base.blog_url,
  raw_input: base.raw_input,
  title: 'Founder Note From Blog',
  draft_text: parsed.founder_note || '',
  bucket: 'Founder Notes',
  status: 'needs_review',
  reviewer: '',
  review_notes: `Hooks: ${(parsed.hooks || []).slice(0, 10).join(' | ')}\nCarousel: ${(parsed.carousel_outline || []).join(' | ')}`
}});
return out;

